*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: ROBERT JOY
// WIDGET BASE: HEADER MENU
//------------------------------------------------------------------------------------------------------------------------
// 2.8   | 2022-06-04 | raj | STRY0118963 - STRY0121797 - Banner Notification Revamp
//                                         New Widget, might be able to merge with Tasker-Header Menu
// 2.8.0 | 2022-08-13 | raj  | STRY0126833 Tasker Portal Homepage- Resize elements to fit for HD1080p at 125% scale
//                                          Changes in bannerMenuTemplate and CSS
// 
//------------------------------------------------------------------------------------------------------------------------
(function(){
	main();

	function main(){

		// build menus
		var menu_id = $sp.getValue('sys_id'); // instance sys_id

		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('tasker_banner_menu');

		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
		data.messages = taskWidgetIconsAndMessage.loadMessages();
		data.icons = taskWidgetIconsAndMessage.loadIcons();

		getMenuItems(menu_id);
		setItemSrcOnAllDescendants(data.menu.items);

		data.isLoggedIn = GlideSession.get().isLoggedIn();
		getGuidedTours();
		loadCatalogCart();

	}
	function getMenuItems(menu_id){
		data.menu = {};
		data.menu.items = $sp.getMenuItems(menu_id);		
	}
	function getGuidedTours(){
		data.guidedTours = {};
		// Show tours only if gtd's sp sys property is set
		data.showTours = (gs.getProperty('com.snc.guided_tours.sp.enable') === 'true') && data.isLoggedIn;
		if (!data.showTours) {
			data.guidedTours = null;
		}
	}
	function loadCatalogCart(){
		var catalogArr = ($sp.getCatalogs().value + "").split(",");

		catalogArr.forEach(function(catalog) {
			data.showWishlist = data.showWishlist || new sn_sc.Catalog(catalog).isWishlistEnabled();
		});
		if (data.isLoggedIn) {
			if (data.showWishlist)
				data.wishlistWidget = $sp.getWidget("sc_wishlist_cart", {wishlistTemplate: "small_wishlist.html", auto_update_wishlist:options.auto_update_wishlist});
			if (gs.getProperty("glide.sc.portal.use_cart_v2_header", "false") === "true")
				data.cartWidget = $sp.getWidget("sc-shopping-cart-v2", {cartTemplate: "small_shopping_cart_v2.html", auto_update_cart:options.auto_update_cart});
			else
				data.cartWidget = $sp.getWidget("sc-shopping-cart", {cartTemplate: "small_shopping_cart.html", auto_update_cart:options.auto_update_cart});
		}
	}
	function setItemSrcOnAllDescendants(items){
		// STRY0114307
		for (var i in items){
			var item = items[i];
			if(item.label){
				var itemLabel = item.label.toString();
				if(itemLabel.toLowerCase().substring(0,6) == 'dtech-'){
					// using the SVG name in the menu item allows us to remove hard coding
					// we can use the svg name to set the svg
					var svgName = itemLabel.substring(6);
					// we can also use svg name to get the title from a message
					var icon = data.icons[svgName];
					item.src = icon.src;
					item.label = icon.title;
				}
			}				
			// if item has href and doesn't have sys_id in href, add the id
			if(item.href && item.href.indexOf("sys_id") == -1){
				item.href = item.href + "&sys_id=" + data.sys_id;
			}

			// if item has items recurse
			if(item.items && item.items.length > 0){
				setItemSrcOnAllDescendants(item.items);
			}
			// process the scripted items also
			if(item.scriptedItems && item.scriptedItems.items && item.scriptedItems.items.length > 0){
				setItemSrcOnAllDescendants(item.scriptedItems.items);
			}
		}

	}	
})();
